// 将 scan-structure 返回的 details 转换为 fixPlan 格式
var details = $scanResult.details;
var fixPlan = {
  headingFixes: [],
  figureFixes: [],
  tableFixes: [],
  formulaFixes: []
};

for (var i = 0; i < details.length; i++) {
  var item = details[i];
  if (item.type === 'heading') {
    fixPlan.headingFixes.push({
      oldNumber: item.old,
      newNumber: item.new
    });
  } else if (item.type === 'figure') {
    fixPlan.figureFixes.push({
      oldNumber: item.old,
      newNumber: item.new
    });
  } else if (item.type === 'table') {
    fixPlan.tableFixes.push({
      oldNumber: item.old,
      newNumber: item.new
    });
  } else if (item.type === 'formula') {
    fixPlan.formulaFixes.push({
      oldNumber: item.old,
      newNumber: item.new
    });
  }
}

return fixPlan;
